# ── CONEXION A SUPABASE (base de datos en la nube) ───────────
# Las credenciales se leen desde Streamlit Secrets (Settings → Secrets en
# Streamlit Cloud). Así NO quedan expuestas en el repo público de GitHub.

SUPABASE_URL = st.secrets["SUPABASE_URL"]
SUPABASE_KEY = st.secrets["SUPABASE_KEY"]

# --- Twilio WhatsApp ---
TWILIO_SID   = st.secrets["TWILIO_SID"]
TWILIO_TOKEN = st.secrets["TWILIO_TOKEN"]
TWILIO_WA    = st.secrets["TWILIO_WA"]   # número sandbox de Twilio

HEADERS = {
    "apikey": SUPABASE_KEY,
    "Authorization": f"Bearer {SUPABASE_KEY}",
    "Content-Type": "application/json"
}


def limpiar_tel(t):
    """Deja solo los digitos del telefono, para guardarlo y buscarlo
    de forma consistente (sin espacios, guiones ni el +)."""
    return "".join(c for c in str(t) if c.isdigit())


def registrar_cliente(nombre, apellido, cedula, telefono, fecha_nacimiento):
    if nombre == "" or apellido == "" or cedula == "" or telefono == "":
        return False, "Todos los campos son obligatorios."
    if not cedula.isdigit():
        return False, "La cedula debe contener solo numeros."
    if not nombre.replace(" ", "").isalpha():
        return False, "El nombre debe contener solo letras."
    if not apellido.replace(" ", "").isalpha():
        return False, "El apellido debe contener solo letras."

    try:
        # Verificar si la cedula ya existe
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/clientes",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            return False, "Esa cedula ya esta registrada."

        # Insertar nuevo cliente
        resp = requests.post(
            f"{SUPABASE_URL}/rest/v1/clientes",
            headers=HEADERS,
            json={
                "cedula": cedula,
                "nombre": nombre,
                "apellido": apellido,
                "telefono": limpiar_tel(telefono),
                "fecha_nacimiento": fecha_nacimiento
            }
        )
        if resp.status_code in (200, 201):
            return True, f"Cliente {nombre} {apellido} registrado correctamente."
        return False, "Error al registrar el cliente. Intenta de nuevo."

    except requests.exceptions.RequestException:
        return False, "Error de conexion con la base de datos."


def buscar_cliente(cedula):
    """Retorna el nombre completo del cliente o None si no existe."""
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/clientes",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}"}
        )
        if resp.status_code == 200:
            data = resp.json()
            if len(data) > 0:
                nombre = data[0].get("nombre", "") or ""
                apellido = data[0].get("apellido", "") or ""
                completo = (nombre + " " + apellido).strip()
                return completo if completo else None
    except requests.exceptions.RequestException:
        pass
    return None


def buscar_cliente_por_telefono(telefono):
    """Retorna la fila del cliente (dict) buscando por telefono, o None.
    Se usa como identificador principal en el flujo de citas."""
    tel = limpiar_tel(telefono)
    if tel == "":
        return None
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/clientes",
            headers=HEADERS,
            params={"telefono": f"eq.{tel}"}
        )
        if resp.status_code == 200:
            data = resp.json()
            if len(data) > 0:
                return data[0]
    except requests.exceptions.RequestException:
        pass
    return None


def agendar_cita(cedula, fecha, hora, peluquero, servicio):
    nombre_cliente = buscar_cliente(cedula)
    if nombre_cliente is None:
        return False, "Cedula no encontrada. El cliente no esta registrado."

    try:
        # Verificar disponibilidad de la hora PARA ESE BARBERO
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            params={"fecha": f"eq.{fecha}", "hora": f"eq.{hora}", "peluquero": f"eq.{peluquero}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            return False, f"{peluquero} ya tiene una cita a las {hora}:00 del {fecha}."

        # Guardar la nueva cita
        resp = requests.post(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            json={"cedula": cedula, "fecha": fecha, "hora": hora, "peluquero": peluquero, "servicio": servicio}
        )
        if resp.status_code in (200, 201):
            return True, f"Cita agendada para {nombre_cliente} el {fecha} a las {hora}:00."
        return False, "Error al agendar la cita. Intenta de nuevo."

    except requests.exceptions.RequestException:
        return False, "Error de conexion con la base de datos."


def buscar_citas_cliente(cedula):
    """Retorna lista de citas del cliente."""
    resultados = []
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}"}
        )
        if resp.status_code == 200:
            for row in resp.json():
                resultados.append({
                    "Fecha": row["fecha"],
                    "Hora": row["hora"] + ":00",
                    "Peluquero": row["peluquero"],
                    "Servicio": row["servicio"]
                })
    except requests.exceptions.RequestException:
        pass
    return resultados


def ver_citas_del_dia(fecha):
    """Retorna lista de citas de una fecha."""
    resultados = []
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            params={"fecha": f"eq.{fecha}"}
        )
        if resp.status_code == 200:
            for row in resp.json():
                nombre = buscar_cliente(row["cedula"]) or "Desconocido"
                resultados.append({
                    "Hora": row["hora"] + ":00",
                    "Cliente": nombre,
                    "Cedula": row["cedula"],
                    "Peluquero": row["peluquero"],
                    "Servicio": row["servicio"]
                })
    except requests.exceptions.RequestException:
        pass
    return resultados


def fecha_valida(fecha_str):
    partes = fecha_str.split("/")
    if len(partes) != 3:
        return False
    dia, mes, anio = partes
    if not dia.isdigit() or not mes.isdigit() or not anio.isdigit():
        return False
    if len(anio) != 4:
        return False
    if not (1 <= int(dia) <= 31):
        return False
    if not (1 <= int(mes) <= 12):
        return False
    return True


def confirmar_asistencia(cedula, fecha, hora):
    """
    Confirma la asistencia de un cliente si faltan 5 horas o menos para su cita.
    Guarda en la tabla confirmados.
    """
    try:
        # Verificar que la cita exista
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}", "fecha": f"eq.{fecha}", "hora": f"eq.{hora}"}
        )
        if resp.status_code != 200 or len(resp.json()) == 0:
            return False, "No se encontro una cita con esos datos."

        # Verificar que no haya confirmado ya
        resp2 = requests.get(
            f"{SUPABASE_URL}/rest/v1/confirmados",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}", "fecha": f"eq.{fecha}", "hora": f"eq.{hora}"}
        )
        if resp2.status_code == 200 and len(resp2.json()) > 0:
            return False, "Esta cita ya fue confirmada anteriormente."

        # Verificar que falten 5 horas o menos
        dia, mes, anio = fecha.split("/")
        hora_cita = datetime(int(anio), int(mes), int(dia), int(hora), 0, 0)
        ahora = ahora_co()
        diferencia_horas = (hora_cita - ahora).total_seconds() / 3600

        if diferencia_horas > 5:
            horas_restantes = round(diferencia_horas, 1)
            return False, f"Solo puedes confirmar cuando falten 5 horas o menos. Faltan {horas_restantes} horas."

        if diferencia_horas < 0:
            return False, "Esta cita ya paso."

        # Guardar confirmacion
        timestamp = ahora_co().strftime("%Y-%m-%d %H:%M:%S")
        resp3 = requests.post(
            f"{SUPABASE_URL}/rest/v1/confirmados",
            headers=HEADERS,
            json={"cedula": cedula, "fecha": fecha, "hora": hora, "timestamp_confirmacion": timestamp}
        )
        if resp3.status_code in (200, 201):
            # Enviar WhatsApp al cliente
            wa_ok, wa_err = False, "Sin teléfono registrado."
            try:
                cita = resp.json()[0]
                peluquero = cita.get("peluquero", "tu barbero")
                servicio  = cita.get("servicio", "")
                rc = requests.get(
                    f"{SUPABASE_URL}/rest/v1/clientes",
                    headers=HEADERS,
                    params={"cedula": f"eq.{cedula}"}
                )
                if rc.status_code == 200 and len(rc.json()) > 0:
                    cliente = rc.json()[0]
                    nombre_cliente = cliente.get("nombre", "Cliente")
                    telefono = cliente.get("telefono", "")
                    if telefono:
                        msg_cliente = (
                            f"✅ *The Club Barbershop*\n"
                            f"Hola {nombre_cliente}, tu cita ha sido confirmada.\n"
                            f"📅 Fecha: {fecha}\n"
                            f"🕐 Hora: {hora}:00\n"
                            f"💈 Barbero: {peluquero}\n"
                            f"✂️ Servicio: {servicio}\n"
                            f"¡Te esperamos!"
                        )
                        wa_ok, wa_err = enviar_whatsapp(telefono, msg_cliente)
            except Exception as e:
                wa_err = str(e)
            if wa_ok:
                return True, "Asistencia confirmada. ¡WhatsApp enviado al cliente!"
            return True, f"Asistencia confirmada. (WhatsApp no enviado: {wa_err})"
        return False, "Error al confirmar. Intenta de nuevo."

    except requests.exceptions.RequestException:
        return False, "Error de conexion con la base de datos."


def esta_confirmada(cedula, fecha, hora):
    """Retorna True si la cita ya fue confirmada."""
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/confirmados",
            headers=HEADERS,
            params={"cedula": f"eq.{cedula}", "fecha": f"eq.{fecha}", "hora": f"eq.{hora}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            return True
    except requests.exceptions.RequestException:
        pass
    return False


def get_citas_confirmadas():
    """Retorna lista de citas que ya confirmaron asistencia."""
    resultados = []
    try:
        resp = requests.get(f"{SUPABASE_URL}/rest/v1/confirmados", headers=HEADERS)
        if resp.status_code == 200:
            for row in resp.json():
                nombre = buscar_cliente(row["cedula"]) or "Desconocido"
                resultados.append({
                    "Cliente": nombre,
                    "Cedula": row["cedula"],
                    "Fecha": row["fecha"],
                    "Hora": row["hora"] + ":00",
                    "Confirmado a las": row["timestamp_confirmacion"]
                })
    except requests.exceptions.RequestException:
        pass
    return resultados


def get_citas_sin_confirmar():
    """Retorna lista de citas que NO han confirmado asistencia."""
    resultados = []
    try:
        resp = requests.get(f"{SUPABASE_URL}/rest/v1/citas", headers=HEADERS)
        if resp.status_code == 200:
            for row in resp.json():
                if not esta_confirmada(row["cedula"], row["fecha"], row["hora"]):
                    nombre = buscar_cliente(row["cedula"]) or "Desconocido"
                    resultados.append({
                        "Cliente": nombre,
                        "Cedula": row["cedula"],
                        "Fecha": row["fecha"],
                        "Hora": row["hora"] + ":00",
                        "Peluquero": row["peluquero"],
                        "Servicio": row["servicio"]
                    })
    except requests.exceptions.RequestException:
        pass
    return resultados


# ── FUNCIONES DE BARBEROS ────────────────────────────────────

DIAS_SEMANA = ["lunes", "martes", "miercoles", "jueves", "viernes", "sabado", "domingo"]


def get_barberos(solo_activos=False):
    """Retorna lista de barberos (dicts). Si solo_activos=True, solo los activos."""
    resultados = []
    try:
        params = {"order": "nombre.asc"}
        if solo_activos:
            params["activo"] = "eq.true"
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            params=params
        )
        if resp.status_code == 200:
            resultados = resp.json()
    except requests.exceptions.RequestException:
        pass
    return resultados


def agregar_barbero(nombre):
    if nombre.strip() == "":
        return False, "El nombre del barbero no puede estar vacio."
    if not nombre.replace(" ", "").isalpha():
        return False, "El nombre debe contener solo letras."
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            params={"nombre": f"eq.{nombre}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            return False, "Ese barbero ya existe."
        resp = requests.post(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            json={"nombre": nombre, "activo": True, "dias_descanso": ""}
        )
        if resp.status_code in (200, 201):
            return True, f"Barbero {nombre} agregado."
        return False, "Error al agregar el barbero."
    except requests.exceptions.RequestException:
        return False, "Error de conexion con la base de datos."


def eliminar_barbero(barbero_id):
    try:
        resp = requests.delete(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            params={"id": f"eq.{barbero_id}"}
        )
        return resp.status_code in (200, 204)
    except requests.exceptions.RequestException:
        return False


def set_activo_barbero(barbero_id, activo):
    try:
        resp = requests.patch(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            params={"id": f"eq.{barbero_id}"},
            json={"activo": activo}
        )
        return resp.status_code in (200, 204)
    except requests.exceptions.RequestException:
        return False


def set_dias_descanso(barbero_id, dias_lista):
    """Guarda los dias de descanso como string separado por comas."""
    dias_str = ",".join(dias_lista)
    try:
        resp = requests.patch(
            f"{SUPABASE_URL}/rest/v1/barberos",
            headers=HEADERS,
            params={"id": f"eq.{barbero_id}"},
            json={"dias_descanso": dias_str}
        )
        return resp.status_code in (200, 204)
    except requests.exceptions.RequestException:
        return False


def horas_ocupadas_barbero(barbero, fecha):
    """Retorna un set con las horas (str) ya reservadas para ese barbero en esa fecha."""
    ocupadas = set()
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/citas",
            headers=HEADERS,
            params={"fecha": f"eq.{fecha}", "peluquero": f"eq.{barbero}"}
        )
        if resp.status_code == 200:
            for row in resp.json():
                ocupadas.add(str(row["hora"]))
    except requests.exceptions.RequestException:
        pass
    return ocupadas


def marcar_asistencia(barbero, fecha, presente):
    """Marca o actualiza la asistencia (vino / no vino) de un barbero en una fecha."""
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/asistencia_barberos",
            headers=HEADERS,
            params={"barbero": f"eq.{barbero}", "fecha": f"eq.{fecha}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            reg_id = resp.json()[0]["id"]
            resp2 = requests.patch(
                f"{SUPABASE_URL}/rest/v1/asistencia_barberos",
                headers=HEADERS,
                params={"id": f"eq.{reg_id}"},
                json={"presente": presente}
            )
            return resp2.status_code in (200, 204)
        resp2 = requests.post(
            f"{SUPABASE_URL}/rest/v1/asistencia_barberos",
            headers=HEADERS,
            json={"barbero": barbero, "fecha": fecha, "presente": presente}
        )
        return resp2.status_code in (200, 201)
    except requests.exceptions.RequestException:
        return False


def get_asistencia(fecha):
    """Retorna un dict {barbero: presente(bool)} para una fecha."""
    estados = {}
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/asistencia_barberos",
            headers=HEADERS,
            params={"fecha": f"eq.{fecha}"}
        )
        if resp.status_code == 200:
            for row in resp.json():
                estados[row["barbero"]] = row["presente"]
    except requests.exceptions.RequestException:
        pass
    return estados


# ── FUNCIONES DE PRECIOS ─────────────────────────────────────

SERVICIOS = ["corte", "barba", "cejas", "corte+barba", "corte+cejas", "corte+barba+cejas", "otros"]


def normalizar_telefono(t):
    """
    Normaliza un número colombiano a formato internacional sin '+'.
    Ejemplos:
      '3155430286'       -> '573155430286'
      '+57 315 543 0286' -> '573155430286'
      '573155430286'     -> '573155430286'
    """
    if not t:
        return ""
    # Quitar todo lo que no sea dígito
    limpio = "".join(c for c in str(t) if c.isdigit())
    # Si tiene 10 dígitos y empieza con 3, es móvil colombiano sin código
    if len(limpio) == 10 and limpio.startswith("3"):
        return "57" + limpio
    return limpio


def enviar_whatsapp(telefono, mensaje):
    """
    Envía un mensaje de WhatsApp vía Twilio.
    telefono: número con o sin código de país (se normaliza automáticamente).
    Retorna (True, '') si OK, (False, error) si falla.
    """
    try:
        numero = normalizar_telefono(telefono)
        if not numero:
            return False, "Teléfono vacío o inválido."
        url = f"https://api.twilio.com/2010-04-01/Accounts/{TWILIO_SID}/Messages.json"
        data = {
            "From": TWILIO_WA,
            "To":   f"whatsapp:+{numero}",
            "Body": mensaje,
        }
        resp = requests.post(url, data=data, auth=(TWILIO_SID, TWILIO_TOKEN), timeout=10)
        if resp.status_code in (200, 201):
            return True, ""
        try:
            err = resp.json().get("message", resp.text)
        except Exception:
            err = resp.text
        return False, f"Twilio {resp.status_code}: {err}"
    except Exception as e:
        return False, str(e)


def get_precios():
    """Retorna dict {servicio: precio} con todos los precios actuales."""
    resultado = {}
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/precios",
            headers=HEADERS
        )
        if resp.status_code == 200:
            for row in resp.json():
                resultado[row["servicio"]] = row["precio"]
    except requests.exceptions.RequestException:
        pass
    return resultado


def set_precio(servicio, precio):
    """Crea o actualiza el precio de un servicio."""
    try:
        # Verificar si ya existe
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/precios",
            headers=HEADERS,
            params={"servicio": f"eq.{servicio}"}
        )
        if resp.status_code == 200 and len(resp.json()) > 0:
            # Actualizar
            resp = requests.patch(
                f"{SUPABASE_URL}/rest/v1/precios",
                headers=HEADERS,
                params={"servicio": f"eq.{servicio}"},
                json={"precio": precio}
            )
        else:
            # Insertar
            resp = requests.post(
                f"{SUPABASE_URL}/rest/v1/precios",
                headers=HEADERS,
                json={"servicio": servicio, "precio": precio}
            )
        return resp.status_code in (200, 201, 204)
    except requests.exceptions.RequestException:
        return False


